import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { 
  Heart, ListPlus, Trash2, Play, Pause, SkipForward, SkipBack, 
  Trophy, Home as HomeIcon, Search, Library, Music2, User, Disc
} from 'lucide-react';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [hoveredCard, setHoveredCard] = useState(null);
  
  const audioRef = useRef(null);
  const navigate = useNavigate();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

  useEffect(() => {
    fetchSongs();
  }, []);

  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải nhạc:", err); }
  };

  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    try {
      const res = await axios.post(`http://localhost:5000/api/songs/like/${songId}`, {
        userId: loggedInUser._id || loggedInUser.id
      });
      setSongs(songs.map(s => s._id === songId ? res.data : s));
    } catch (err) { console.error(err); }
  };

  const handleCreatePlaylist = async () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    const title = prompt("Tên Playlist mới của bạn:");
    if (!title) return;
    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title, userId: loggedInUser._id, songIds: []
      });
      alert("Đã tạo Playlist thành công! 🎉");
    } catch (err) { alert("Lỗi tạo playlist"); }
  };

  const playSong = (index) => { setCurrentIndex(index); setIsPlaying(true); };
  
  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) audioRef.current.pause();
    else audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  const formatTime = (t) => {
    if (isNaN(t)) return "0:00";
    const m = Math.floor(t / 60);
    const s = Math.floor(t % 60);
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  return (
    <div style={containerStyle}>
      {/* 1. SIDEBAR LEFT */}
      <div style={sidebarStyle}>
        <div style={logoStyle} onClick={() => navigate('/')}>P2TUNES</div>
        
        <div style={menuGroup}>
          <div style={menuItemActive}><HomeIcon size={22}/> Trang chủ</div>
          <div style={menuItem}><Search size={22}/> Tìm kiếm</div>
          <div style={menuItem} onClick={() => navigate('/ranking')}><Trophy size={22}/> Bảng xếp hạng</div>
        </div>

        <div style={menuGroup}>
          <p style={menuTitle}>THƯ VIỆN CỦA BẠN</p>
          <div style={menuItem}><Library size={22}/> Danh sách phát</div>
          <div style={menuItem}><Heart size={22}/> Bài hát đã thích</div>
          
          {/* NÚT TẠO PLAYLIST ĐÃ SỬA: CHỮ ĐEN, ĐẬM, NỀN TRẮNG */}
          <button 
            onClick={handleCreatePlaylist} 
            style={sidebarAddBtn}
            onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.03)'}
            onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}
          >
            <ListPlus size={20} color="#000" strokeWidth={3} /> 
            TẠO PLAYLIST
          </button>
        </div>
      </div>

      {/* 2. MAIN CONTENT AREA */}
      <div style={mainContentStyle}>
        {/* Banner Chào mừng */}
        <div style={heroBanner}>
          <div style={{zIndex: 2, position: 'relative'}}>
            <h1 style={{fontSize: '48px', margin: '0 0 10px 0', fontWeight: '800'}}>
              Chào {loggedInUser?.username || 'Bạn'}! 👋
            </h1>
            <p style={{opacity: 0.9, fontSize: '18px', maxWidth: '500px'}}>
              Hôm nay bạn muốn nghe giai điệu gì? Khám phá ngay những bản nhạc mới nhất.
            </p>
          </div>
          <div style={heroOverlay}></div>
        </div>

        {/* Nội dung chính: Grid nhạc */}
        <div style={{padding: '30px 40px'}}>
          <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px'}}>
            <h2 style={{fontSize: '24px', display: 'flex', alignItems: 'center', gap: '10px'}}>
              <Disc color="#1db954" className={isPlaying ? 'spin' : ''} /> Mới phát hành
            </h2>
          </div>
          
          <div style={songGrid}>
            {songs.map((song, index) => (
              <div 
                key={song._id} 
                style={{
                  ...songCardStyle,
                  transform: hoveredCard === song._id ? 'translateY(-8px)' : 'none',
                  backgroundColor: hoveredCard === song._id ? '#2c2c2c' : '#181818'
                }}
                onMouseEnter={() => setHoveredCard(song._id)}
                onMouseLeave={() => setHoveredCard(null)}
              >
                <div style={cardImageWrapper}>
                  <img src={`http://localhost:5000${song.imageUrl}`} style={cardImg} alt="cover" />
                  {hoveredCard === song._id && (
                    <button onClick={() => playSong(index)} style={cardPlayBtn}>
                      <Play fill="black" size={24} />
                    </button>
                  )}
                </div>
                
                <div style={{marginTop: '15px'}}>
                  <div style={songTitle}>{song.title}</div>
                  <div style={songArtist}>{song.artist}</div>
                </div>
                
                <div style={cardFooter}>
                   <div onClick={() => navigate(`/profile/${song.userId}`)} style={uploaderLink}>
                     @{song.uploaderName || "User"}
                   </div>
                   <button onClick={() => handleLike(song._id)} style={likeBtn}>
                      <Heart 
                        size={18} 
                        fill={song.likes?.includes(loggedInUser?._id) ? "#1db954" : "none"} 
                        color={song.likes?.includes(loggedInUser?._id) ? "#1db954" : "#888"}
                      />
                      <span style={{fontSize: '13px', fontWeight: 'bold'}}>{song.likes?.length || 0}</span>
                   </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* 3. FLOATING PLAYER BAR (Glassmorphism) */}
      {currentSong && (
        <div style={playerBarStyle}>
          <div style={playerLeft}>
            <img src={`http://localhost:5000${currentSong.imageUrl}`} style={playerImg} alt="" />
            <div style={{overflow: 'hidden'}}>
              <div style={{fontWeight: 'bold', fontSize: '15px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis'}}>{currentSong.title}</div>
              <div style={{fontSize: '13px', color: '#b3b3b3'}}>{currentSong.artist}</div>
            </div>
          </div>

          <div style={playerCenter}>
            <div style={controls}>
              <SkipBack size={24} style={iconBtn} onClick={() => setCurrentIndex((currentIndex - 1 + songs.length) % songs.length)} />
              <button onClick={togglePlay} style={playMainBtn}>
                {isPlaying ? <Pause size={26} fill="black" /> : <Play size={26} fill="black" />}
              </button>
              <SkipForward size={24} style={iconBtn} onClick={() => setCurrentIndex((currentIndex + 1) % songs.length)} />
            </div>
            <div style={progressArea}>
              <span style={timeText}>{formatTime(currentTime)}</span>
              <input 
                type="range" min="0" max={duration || 0} value={currentTime} 
                onChange={(e) => { audioRef.current.currentTime = e.target.value; setCurrentTime(e.target.value); }}
                style={progressBar} 
              />
              <span style={timeText}>{formatTime(duration)}</span>
            </div>
            <audio 
              ref={audioRef} 
              src={`http://localhost:5000${currentSong.songUrl}`} 
              autoPlay 
              onEnded={() => setCurrentIndex((currentIndex + 1) % songs.length)} 
              onTimeUpdate={() => setCurrentTime(audioRef.current.currentTime)} 
              onLoadedMetadata={() => setDuration(audioRef.current.duration)} 
            />
          </div>

          <div style={playerRight}>
             <div onClick={() => navigate(`/profile/${loggedInUser?._id}`)} style={userAccountStyle}>
                <User size={20} />
                <span>{loggedInUser?.username}</span>
             </div>
          </div>
        </div>
      )}

      {/* CSS Animation cho đĩa xoay */}
      <style>{`
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .spin { animation: spin 3s linear infinite; }
      `}</style>
    </div>
  );
};

/* --- STYLE OBJECTS (CHUYÊN NGHIỆP) --- */
const containerStyle = { display: 'flex', height: '100vh', backgroundColor: '#000', color: '#fff', fontFamily: "'Segoe UI', Roboto, Helvetica, Arial, sans-serif", overflow: 'hidden' };

const sidebarStyle = { width: '280px', backgroundColor: '#000', padding: '24px', display: 'flex', flexDirection: 'column', gap: '35px', borderRight: '1px solid #222' };
const logoStyle = { fontSize: '32px', fontWeight: '900', color: '#1db954', cursor: 'pointer', letterSpacing: '-1.5px' };
const menuGroup = { display: 'flex', flexDirection: 'column', gap: '20px' };
const menuTitle = { fontSize: '11px', fontWeight: '800', color: '#b3b3b3', letterSpacing: '1.5px', marginBottom: '5px' };
const menuItem = { display: 'flex', alignItems: 'center', gap: '16px', color: '#b3b3b3', cursor: 'pointer', fontWeight: '700', transition: '0.2s', fontSize: '15px' };
const menuItemActive = { ...menuItem, color: '#fff' };

// STYLE NÚT TẠO PLAYLIST (ĐÃ NÂNG CẤP)
const sidebarAddBtn = { 
    marginTop: '10px', 
    background: '#ffffff', 
    color: '#000000', 
    border: 'none', 
    padding: '14px 22px', 
    borderRadius: '30px', 
    cursor: 'pointer', 
    display: 'flex', 
    alignItems: 'center', 
    gap: '10px', 
    fontSize: '13px', 
    fontWeight: '900',         // SIÊU ĐẬM
    textTransform: 'uppercase', // IN HOA
    transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
    boxShadow: '0 4px 15px rgba(255,255,255,0.15)'
};

const mainContentStyle = { flex: 1, overflowY: 'auto', background: 'linear-gradient(to bottom, #1a1a1a, #121212)', paddingBottom: '150px' };
const heroBanner = { 
    height: '350px', 
    padding: '0 60px 40px 60px', 
    position: 'relative', 
    display: 'flex', 
    alignItems: 'flex-end', 
    background: 'url("https://images.unsplash.com/photo-1493225255756-d9584f8606e9?q=80&w=2070&auto=format&fit=crop")', 
    backgroundSize: 'cover', 
    backgroundPosition: 'center', 
    margin: '20px', 
    borderRadius: '24px' 
};
const heroOverlay = { position: 'absolute', top: 0, left: 0, right: 0, bottom: 0, background: 'linear-gradient(rgba(0,0,0,0), rgba(0,0,0,0.8))', borderRadius: '24px' };

const songGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '30px' };
const songCardStyle = { padding: '20px', borderRadius: '16px', transition: '0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)', cursor: 'pointer' };
const cardImageWrapper = { position: 'relative', width: '100%', aspectRatio: '1/1', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.5)' };
const cardImg = { width: '100%', height: '100%', objectFit: 'cover' };
const cardPlayBtn = { position: 'absolute', bottom: '15px', right: '15px', width: '52px', height: '52px', borderRadius: '50%', backgroundColor: '#1db954', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 8px 20px rgba(0,0,0,0.4)', cursor: 'pointer' };
