const songArtist = { color: '#b3b3b3', fontSize: '14px', marginTop: '6px' };
const cardFooter = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '18px' };
const uploaderLink = { fontSize: '13px', color: '#1db954', fontWeight: '700', opacity: 0.9 };
const likeBtn = { background: 'rgba(255,255,255,0.05)', border: 'none', color: '#888', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', padding: '6px 12px', borderRadius: '15px' };

const playerBarStyle = { position: 'fixed', bottom: '25px', left: '25px', right: '25px', height: '100px', background: 'rgba(28, 28, 28, 0.75)', backdropFilter: 'blur(25px)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '50px', display: 'flex', alignItems: 'center', padding: '0 35px', zIndex: 1000, boxShadow: '0 15px 35px rgba(0,0,0,0.6)' };
const playerLeft = { width: '30%', display: 'flex', alignItems: 'center', gap: '18px' };
const playerImg = { width: '64px', height: '64px', borderRadius: '12px', objectFit: 'cover', boxShadow: '0 4px 12px rgba(0,0,0,0.4)' };
const playerCenter = { flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center' };
const controls = { display: 'flex', alignItems: 'center', gap: '30px', marginBottom: '10px' };
const playMainBtn = { width: '46px', height: '46px', borderRadius: '50%', backgroundColor: '#fff', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', transition: '0.2s' };
const iconBtn = { cursor: 'pointer', color: '#b3b3b3', transition: '0.2s', hover: { color: '#fff' } };
const progressArea = { display: 'flex', alignItems: 'center', gap: '12px', width: '100%', maxWidth: '600px' };
const timeText = { fontSize: '12px', color: '#a7a7a7', minWidth: '40px', fontWeight: '600' };
const progressBar = { flex: 1, accentColor: '#1db954', height: '5px', cursor: 'pointer' };
const playerRight = { width: '30%', display: 'flex', justifyContent: 'flex-end' };
const userAccountStyle = { display: 'flex', alignItems: 'center', gap: '10px', background: 'rgba(255,255,255,0.1)', padding: '10px 18px', borderRadius: '25px', cursor: 'pointer', fontWeight: '700', fontSize: '14px' };

export default Home;
